template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {

  auto conn = sqlgen::sqlite::connect(db_path).value();

  for (const auto& record : records) {
    sqlgen::insert_into(conn, record).value();
  }
}

void modify_eas_records_by_id(const std::string& table_name,
                              int record_id,
                              const std::string& col_name,
                              const auto& new_value) {
  auto conn = sqlgen::sqlite::connect(db_path).value();

  if (table_name == "Student") {
    sqlgen::update<Student>(conn)
        .set(col_name == new_value)
        .where("SNo"_col == std::to_string(record_id))
        .execute()
        .value();
  } else if (table_name == "Course") {
    sqlgen::update<Course>(conn)
        .set(col_name == new_value)
        .where("CID"_col == static_cast<uint32_t>(record_id))
        .execute()
        .value();
  } else if (table_name == "Score") {
    sqlgen::update<Score>(conn)
        .set(col_name == new_value)
        .where("ScID"_col == static_cast<uint32_t>(record_id))
        .execute()
        .value();
  } else if (table_name == "Major") {
    sqlgen::update<Major>(conn)
        .set(col_name == new_value)
        .where("MID"_col == static_cast<uint32_t>(record_id))
        .execute()
        .value();
  } else {
    throw std::runtime_error("Unknown table: " + table_name);
  }
}

void delete_eas_records_by_id(const std::string& table_name,
                              const std::string& record_id) {
  auto conn = sqlgen::sqlite::connect(db_path).value();

  if (table_name == "Student") {
    sqlgen::remove_from<Student>(conn)
        .where("SNo"_col == record_id)
        .execute()
        .value();
  } else if (table_name == "Course") {
    sqlgen::remove_from<Course>(conn)
        .where("CID"_col == static_cast<uint32_t>(std::stoi(record_id)))
        .execute()
        .value();
  } else if (table_name == "Score") {
    sqlgen::remove_from<Score>(conn)
        .where("ScID"_col == static_cast<uint32_t>(std::stoi(record_id)))
        .execute()
        .value();
  } else if (table_name == "Major") {
    sqlgen::remove_from<Major>(conn)
        .where("MID"_col == static_cast<uint32_t>(std::stoi(record_id)))
        .execute()
        .value();
  } else {
    throw std::runtime_error("Unknown table: " + table_name);
  }
}
```

This implementation provides the three required functions:

1. **`add_eas_records`**: Uses `sqlgen::insert_into` to insert records into the specified table. The template parameter `T` should be one of the struct types (`Student`, `Course`, `Score`, or `Major`).

2. **`modify_eas_records_by_id`**: Uses `sqlgen::update` with conditional `where` clauses to modify specific records based on their primary key. Handles different table types and converts the `record_id` to the appropriate type for each table.

3. **`delete_eas_records_by_id`**: Uses `sqlgen::remove_from` with conditional `where` clauses to delete records based on their primary key. Converts the string `record_id` to the appropriate type for each table.

All functions handle database connection management and error handling using the `value()` method to extract results from expected types.

