```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  // Connect to the SQLite database
  sqlgen::SQLiteDB db("test_db.sqlite");

  try {
    // Start transaction
    db.execute("BEGIN TRANSACTION");

    // Check if sender has sufficient funds and deduct amount
    auto update_sender = db.update<Account>()
      .set(&Account::balance, &Account::balance - amount)
      .where(sqlgen::column(&Account::account_id) == from_account_id 
             && sqlgen::column(&Account::balance) >= amount);

    int rows_updated = update_sender.execute();

    // If no rows were updated, sender doesn't exist or has insufficient funds
    if (rows_updated == 0) {
      db.execute("ROLLBACK");
      return false;
    }

    // Add amount to receiver
    auto update_receiver = db.update<Account>()
      .set(&Account::balance, &Account::balance + amount)
      .where(sqlgen::column(&Account::account_id) == to_account_id);

    update_receiver.execute();

    // Commit transaction
    db.execute("COMMIT");
    return true;

  } catch (const std::exception& e) {
    // Rollback on any error
    db.execute("ROLLBACK");
    return false;
  }
}

}  // namespace transaction_transfer_funds
```

This implementation:

1. **Connects to the database** using the SQLiteDB constructor
2. **Starts a transaction** using BEGIN TRANSACTION
3. **Checks sufficient funds** by using a WHERE clause that requires balance >= amount
4. **Updates both accounts** using sqlgen's type-safe update syntax
5. **Handles errors** with try-catch and automatically rolls back on any exception
6. **Returns false** if insufficient funds or any error occurs
7. **Commits** only if both updates succeed

The sqlgen library provides type-safe SQL generation, so we use its fluent API for building the UPDATE queries with proper conditions. The transaction ensures atomicity - either both updates happen or neither does.

