 * It returns a vector of DepProj structs, where each struct contains the department name (if available) and the project name.
 * Returns: std::vector<DepProj>.
 */
std::vector<DepProj> right_join_departments_projects() {
  // Connect to the SQLite database
  auto db = sqlgen::sqlite::connect("test_db.sqlite");

  // Perform RIGHT JOIN between departments and projects
  // Note: Since SQLite doesn't natively support RIGHT JOIN, we simulate it with LEFT JOIN
  // by swapping the tables and using the appropriate join condition
  auto query = sqlgen::left_join<Project, Department>(db)
    .on<&Project::department_id, &Department::department_id>()
    .select(
      sqlgen::column<&Department::name>().as("department_name"),
      sqlgen::column<&Project::name>().as("project_name")
    );

  std::vector<DepProj> results;

  // Iterate through the query results and populate the vector
  for (auto&& row : query) {
    DepProj depProj;

    // Get department name (optional since it's a RIGHT JOIN)
    auto deptName = row.template get<"department_name">();
    if (deptName.has_value()) {
      depProj.department_name = deptName.value();
    }

    // Get project name
    depProj.project_name = row.template get<"project_name">().value_or("");

    results.push_back(std::move(depProj));
  }

  return results;
}

}  // namespace right_join_departments_projects
