```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <string>

namespace analyze_social_network {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::string email;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> join_date;
  std::optional<std::string> city;
};

struct Friendship {
  int user1_id;
  int user2_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
};

struct MutualFriends {
  std::string user1_name;
  std::string user2_name;
  int mutual_friends_count;
};

struct UserFriendCount {
  int user_id;
  std::string username;
  int friend_count;
};

struct FriendRecommendation {
  std::string user1_name;
  std::string user2_name;
  std::string city;
};

/**
 * Analyze social network data by creating temporary SQL tables for User and Friendship.
 * Returns: std::vector<FriendConnection>.
 */
std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
    // Create an in-memory SQLite database
    sqlgen::SQLiteDB db(":memory:");

    // Create User table
    db.execute(R"(
        CREATE TABLE User (
            user_id INTEGER PRIMARY KEY,
            username VARCHAR(50) NOT NULL UNIQUE,
            email VARCHAR(100) NOT NULL UNIQUE,
            join_date DATETIME NOT NULL,
            city VARCHAR(50)
    )");

    // Create Friendship table
    db.execute(R"(
        CREATE TABLE Friendship (
            user_id1 INTEGER,
            user_id2 INTEGER,
            friendship_date DATETIME NOT NULL,
            PRIMARY KEY (user_id1, user_id2),
            FOREIGN KEY (user_id1) REFERENCES User(user_id),
            FOREIGN KEY (user_id2) REFERENCES User(user_id)
        )
    )");

    // Insert users
    for (const auto& user : users) {
        db.execute("INSERT INTO User (user_id, username, email, join_date, city) VALUES (?, ?, ?, ?, ?)",
                  user.user_id, user.username, user.email, user.join_date, user.city);
    }

    // Insert friendships
    for (const auto& friendship : friendships) {
        db.execute("INSERT INTO Friendship (user_id1, user_id2, friendship_date) VALUES (?, ?, ?)",
                  friendship.user1_id, friendship.user2_id, friendship.created_at);
    }

    // 1. Use SELF-JOIN to find mutual friends (friends who share the same friend)
    auto mutual_friends = db.query<MutualFriends>(R"(
        SELECT u1.username as user1_name, u2.username as user2_name, COUNT(DISTINCT f1.user_id2) as mutual_friends_count
        FROM User u1
        INNER JOIN Friendship f1 ON u1.user_id = f1.user_id1
        INNER JOIN Friendship f2 ON f1.user_id2 = f2.user_id1
        INNER JOIN User u2 ON f2.user_id2 = u2.user_id
        WHERE u1.user_id < u2.user_id
          AND EXISTS (
            SELECT 1 FROM Friendship f3 
            WHERE f3.user_id1 = u1.user_id AND f3.user_id2 = u2.user_id
          )
        GROUP BY u1.user_id, u2.user_id
        HAVING COUNT(DISTINCT f1.user_id2) > 0
    )");

    // 2. Use nested query to find users with more than average number of friends
    auto popular_users = db.query<UserFriendCount>(R"(
        SELECT u.user_id, u.username, COUNT(f.user_id2) as friend_count
        FROM User u
        LEFT JOIN Friendship f ON u.user_id = f.user_id1
        GROUP BY u.user_id, u.username
        HAVING friend_count > (
          SELECT AVG(friend_count) 
          FROM (SELECT COUNT(*) as friend_count FROM Friendship GROUP BY user_id1) as subq
        )
        ORDER BY friend_count DESC
    )");

    // 3. Find friend-of-friend relationships (people connected through exactly one mutual friend)
    auto friend_of_friend = db.query<FriendConnection>(R"(
        SELECT u1.username as user1_name, u2.username as user2_name
        FROM User u1
        INNER JOIN Friendship f1 ON u1.user_id = f1.user_id1
        INNER JOIN Friendship f2 ON f1.user_id2 = f2.user_id1
        INNER JOIN User u2 ON f2.user_id2 = u2.user_id
        WHERE u1.user_id != u2.user_id
          AND NOT EXISTS (
            SELECT 1 FROM Friendship f3 
            WHERE f3.user_id1 = u1.user_id AND f3.user_id2 = u2.user_id
          )
        GROUP BY u1.user_id, u2.user_id
        HAVING COUNT(DISTINCT f1.user_id2) = 1
    )");

    // 4. Count friends per user and identify most connected users
    auto friend_counts = db.query<UserFriendCount>(R"(
        SELECT u.user_id, u.username, COUNT(f.user_id2) as friend_count
        FROM User u
        LEFT JOIN Friendship f ON u.user_id = f.user_id1
        GROUP BY u.user_id, u.username
        ORDER BY friend_count DESC
    )");

    // 5. Find users in the same city who are not yet friends (recommendation)
    auto recommendations = db.query<FriendRecommendation>(R"(
        SELECT u1.username as user1_name, u2.username as user2_name, u1.city as city
        FROM User u1
        INNER JOIN User u2 ON u1.city = u2.city AND u1.user_id < u2.user_id
        WHERE u1.city IS NOT NULL
          AND NOT EXISTS (
            SELECT 1 FROM Friendship f 
            WHERE (f.user_id1 = u1.user_id AND f.user_id2 = u2.user_id)
               OR (f.user_id1 = u2.user_id AND f.user_id2 = u1.user_id)
          )
        ORDER BY u1.city, u1.username, u2.username
    )");

    // Return the friend-of-friend relationships as the main result
    return friend_of_friend;
}

}  // namespace analyze_social_network
```

This implementation:

1. **Creates the required tables** with proper constraints and foreign key relationships
2. **Inserts the provided data** from the input vectors into the database
3. **Performs all the required queries** using SQLite with `sqlgen`:
   - Mutual friends using SELF-JOIN
   - Popular users using nested subqueries
   - Friend-of-friend relationships
   - Friend counts per user
   - Friend recommendations based on city

4. **Uses proper data structures** for each query result type
5. **Returns friend-of-friend relationships** as the main result vector

The code handles all the SQL operations through the `sqlgen` library while maintaining type safety and proper error handling through the library's mechanisms.

