std::vector<MathAnalysis> analyze_mathematical_operations(const std::vector<Product>& products) {
  // Create SQLite database connection
  sqlgen::SQLiteDB db("test_db.sqlite");

  // Create Product table
  db.execute(R"(
    CREATE TABLE IF NOT EXISTS Product (
      product_id INTEGER PRIMARY KEY,
      name TEXT NOT NULL,
      price REAL NOT NULL,
      quantity INTEGER NOT NULL,
      discount_rate REAL NOT NULL
    )
  )");

  // Clear existing data
  db.execute("DELETE FROM Product");

  // Insert products
  auto insert_stmt = db.prepare(R"(
    INSERT INTO Product (product_id, name, price, quantity, discount_rate)
    VALUES (?, ?, ?, ?, ?)
  )");

  for (const auto& product : products) {
    insert_stmt.bind(1, product.product_id.value);
    insert_stmt.bind(2, product.name);
    insert_stmt.bind(3, product.price);
    insert_stmt.bind(4, product.quantity);
    insert_stmt.bind(5, product.discount_rate);
    insert_stmt.execute();
    insert_stmt.reset();
  }

  // Perform mathematical analysis
  auto query = db.prepare(R"(
    SELECT 
      product_id,
      name,
      ABS(price) as abs_price,
      CEIL(price) as ceil_price,
      FLOOR(price) as floor_price,
