 * @return std::vector<OrderMetrics> Analysis results for each order item.
 */
std::vector<OrderMetrics> calculate_order_metrics_impl(const std::vector<OrderItem>& items) {
  // Create SQLite database connection
  sqlgen::SQLite3 db("test_db.sqlite");

  // Create temporary table for OrderItem data
  db.execute(R"(
    CREATE TEMPORARY TABLE temp_OrderItem (
      item_id INTEGER PRIMARY KEY,
      order_id INTEGER NOT NULL,
      product_id INTEGER NOT NULL,
      unit_price REAL NOT NULL,
      quantity INTEGER NOT NULL,
      discount_rate REAL,
      tax_rate REAL
    )
  )");

  // Insert all items into the temporary table
  for (const auto& item : items) {
    db.execute(R"(
      INSERT INTO temp_OrderItem (item_id, order_id, product_id, unit_price, quantity, discount_rate, tax_rate)
      VALUES (?, ?, ?, ?, ?, ?, ?)
    )", item.item_id.value(), item.order_id, item.product_id, item.unit_price, 
       item.quantity, item.discount_rate.value_or(0.0), item.tax_rate.value_or(0.0));
  }

  // Execute the comprehensive metrics calculation query
  auto results = db.select<OrderMetrics>(R"(
    SELECT 
      item_id,
      order_id,
      product_id,
      unit_price,
      quantity,
      COALESCE(discount_rate, 0.0) as discount_rate,
      COALESCE(tax_rate, 0.0) as tax_rate,
      (unit_price * quantity) as gross_total,
      (unit_price * quantity * (1 - COALESCE(discount_rate, 0.0)/100)) as discounted_total,
      (unit_price * quantity * (1 - COALESCE(discount_rate, 0.0)/100) * (1 + COALESCE(tax_rate, 0.0)/100)) as final_total,
      (unit_price * quantity / quantity) as unit_cost,
      (quantity % 10) as quantity_group,
      (unit_price * 0.3) as estimated_profit
    FROM temp_OrderItem
    ORDER BY item_id
  )");

  // Clean up temporary table
  db.execute("DROP TABLE IF EXISTS temp_OrderItem");

  return results;
}

}  // namespace calculate_order_metrics
