#include <algorithm>

namespace replace_text_in_notes {

struct Note {
  sqlgen::PrimaryKey<int> note_id;
  std::string content;
};

struct UpdatedNote {
  sqlgen::PrimaryKey<int> note_id;
  std::string updated_content;
};

/**
 * description: replace_text_in_notes.
 * This function demonstrates how to replace text in notes using sqlgen update API.
 * It replaces all occurrences of "foo" with "bar" in the content column of the Note table.
 * Returns: std::vector<UpdatedNote>.
 */
std::vector<UpdatedNote> replace_text_in_notes() {
  // Connect to the SQLite database
  sqlgen::SQLiteDB db("test_db.sqlite");

  // Create table mapping for Notes
  sqlgen::Table<Note> notes_table("Notes", &Note::note_id, &Note::content);

  // Fetch all notes from the database
  auto notes = notes_table.select_all(db);

  std::vector<UpdatedNote> updated_notes;

  // Process each note
  for (auto& note : notes) {
    // Replace "foo" with "bar" in the content
    std::string original_content = note.content;
    std::string updated_content = original_content;

    // Perform the replacement
    size_t pos = 0;
    while ((pos = updated_content.find("foo", pos)) != std::string::npos) {
      updated_content.replace(pos, 3, "bar");
      pos += 3; // Move past the replacement
    }

    // Update the note in the database if content changed
    if (original_content != updated_content) {
      note.content = updated_content;
      notes_table.update(db, note);
    }

    // Add to result vector for verification
    UpdatedNote updated_note;
    updated_note.note_id = note.note_id;
    updated_note.updated_content = updated_content;
    updated_notes.push_back(updated_note);
  }

  return updated_notes;
}

}  // namespace replace_text_in_notes
