    Account account2{0, 2500.0, "active"};
    Account account3{0, 500.0, "inactive"};

    insert_stmt.execute(account1.balance, account1.status);
    insert_stmt.execute(account2.balance, account2.status);
    insert_stmt.execute(account3.balance, account3.status);

    // 4. Update balances and statuses using set operations
    // Update all active accounts to increase balance by 10%
    auto update_balance_stmt = db.prepare<Account>(
        sqlgen::update<Account>()
            .set(sqlgen::field<&Account::balance>())
            .where(sqlgen::field<&Account::status>() == "active")
    );

    // Update specific account's status
    auto update_status_stmt = db.prepare<Account>(
        sqlgen::update<Account>()
            .set(sqlgen::field<&Account::status>())
            .where(sqlgen::field<&Account::account_id>() == 3)
    );

    // Execute updates
    update_balance_stmt.execute(1100.0);  // Update account_id 1 and 2 balances
    update_status_stmt.execute("active"); // Update account_id 3 status

    // 5. Verify changes persisted
    auto select_stmt = db.prepare<Account>(
        sqlgen::select<Account>()
    );

    auto results = select_stmt.execute();
    std::vector<Account> updated_accounts;

    for (const auto& row : results) {
        updated_accounts.push_back(row);
    }

    // Verify the updates
    bool success = true;

    // Check account 1: balance should be 1100.0, status "active"
    if (updated_accounts.size() >= 1) {
        if (std::abs(updated_accounts[0].balance - 1100.0) > 0.001 || 
            updated_accounts[0].status != "active") {
            success = false;
        }
    }

    // Check account 2: balance should be 1100.0, status "active"  
    if (updated_accounts.size() >= 2) {
        if (std::abs(updated_accounts[1].balance - 1100.0) > 0.001 || 
            updated_accounts[1].status != "active") {
            success = false;
