    }

    // Check account 3: status should be "active" now
    if (updated_accounts.size() >= 3) {
        if (updated_accounts[2].status != "active") {
            success = false;
        }
    }

    // Clean up
    db.execute("DROP TABLE IF EXISTS Account;");

    return success;

  } catch (const std::exception& e) {
    std::cerr << "Error in update_set_operations: " << e.what() << std::endl;
    return false;
  }
}

