Here's the complete implementation of the function using the `sqlgen` library:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace full_join_suppliers_products {

struct Supplier {
  sqlgen::PrimaryKey<int> supplier_id;
  std::string name;
};

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int supplier_id;
  std::string name;
};

struct SupProd {
  std::string supplier_name;
  std::optional<std::string> product_name;
};

/**
 * Returns a vector of SupProd structs, where each struct contains the name of a supplier and the name of a product, if any.
 */
std::vector<SupProd> full_join_suppliers_products() {
  // Connect to the SQLite database
  auto db = sqlgen::sqlite::connect("test_db.sqlite");

  // Since SQLite doesn't natively support FULL JOIN, we simulate it using UNION of LEFT and RIGHT JOINs
  // First part: LEFT JOIN (all suppliers with their products, if any)
  auto left_join_query = sqlgen::query<Supplier>()
    .left_join<Product>(sqlgen::on(&Supplier::supplier_id, &Product::supplier_id))
    .select(sqlgen::columns(&Supplier::name, &Product::name));

  auto left_results = db.execute(left_join_query);

  // Second part: RIGHT JOIN simulation using LEFT JOIN with reversed tables
  // (all products with their suppliers, if any, excluding matches already in left join)
  auto right_join_query = sqlgen::query<Product>()
    .left_join<Supplier>(sqlgen::on(&Product::supplier_id, &Supplier::supplier_id))
    .where(sqlgen::is_null(&Supplier::supplier_id))
    .select(sqlgen::columns(&Supplier::name, &Product::name));

  auto right_results = db.execute(right_join_query);

  // Combine results
  std::vector<SupProd> results;

  // Process left join results (suppliers with optional products)
  for (const auto& row : left_results) {
    SupProd item;
    item.supplier_name = std::get<0>(row);
    auto product_name = std::get<1>(row);
    if (!product_name.empty()) {
      item.product_name = product_name;
    }
    results.push_back(item);
  }

  // Process right join results (products without suppliers)
  for (const auto& row : right_results) {
    SupProd item;
    auto supplier_name = std::get<0>(row);
    // For products without suppliers, supplier_name will be empty/null
    item.supplier_name = supplier_name.empty() ? "No Supplier" : supplier_name;
    item.product_name = std::get<1>(row);
    results.push_back(item);
  }

  return results;
}

}  // namespace full_join_suppliers_products
```

**Alternative implementation using a more direct approach:**

If you prefer a more concise implementation that uses a single query with UNION to simulate FULL JOIN (which is the standard way in SQLite), here's an alternative version:

```cpp
