#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace full_join_suppliers_products {

struct Supplier {
  sqlgen::PrimaryKey<int> supplier_id;
  std::string name;
};

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int supplier_id;
  std::string name;
};

struct SupProd {
  std::string supplier_name;
  std::optional<std::string> product_name;
};

/**
 * Returns a vector of SupProd structs, where each struct contains the name of a supplier and the name of a product, if any.
 */
std::vector<SupProd> full_join_suppliers_products() {
  // Connect to the SQLite database
  auto db = sqlgen::sqlite::connect("test_db.sqlite");

  // Since SQLite doesn't support FULL JOIN directly, we use UNION of LEFT JOIN and RIGHT JOIN simulation
  // This is the standard way to simulate FULL JOIN in SQLite
  auto query = sqlgen::query<Supplier>()
    .left_join<Product>(sqlgen::on(&Supplier::supplier_id, &Product::supplier_id))
    .select(sqlgen::columns(&Supplier::name, &Product::name))
    .union_all(
      sqlgen::query<Product>()
        .left_join<Supplier>(sqlgen::on(&Product::supplier_id, &Supplier::supplier_id))
        .where(sqlgen::is_null(&Supplier::supplier_id))
        .select(sqlgen::columns(&Supplier::name, &Product::name))
    );

  auto db_results = db.execute(query);

  std::vector<SupProd> results;

  for (const auto& row : db_results) {
    SupProd item;
    item.supplier_name = std::get<0>(row);
    auto product_name = std::get<1>(row);
    if (!product_name.empty()) {
      item.product_name = product_name;
    }
    results.push_back(item);
  }

  return results;
}

}  // namespace full_join_suppliers_products
```

Both implementations will:
1. Connect to the SQLite database "test_db.sqlite"
2. Perform a FULL JOIN equivalent between Supplier and Product tables
3. Include all suppliers (even those without products)
4. Include all products (even those without suppliers)
5. Return the combined results in a vector of SupProd structs

The key points:
- SQLite doesn't natively support FULL JOIN, so we simulate it using UNION of LEFT JOIN and a reversed LEFT JOIN
- The `std::optional<std::string>` for product_name correctly handles cases where a supplier has no products
- The implementation follows the sqlgen library's fluent API style

